  SCM: [
    { label: 'Novo Relatório' },
    { label: 'Licenças SCM' },
    { label: 'Relatórios SCM' }
  ],
  TVpA: [
    { label: 'Novo Relatório' },
    { label: 'Licenças TVpA' },
    { label: 'Relatórios TVpA' }
  ],
  STFC: [
    { label: 'Novo Relatório STFC' },
    { label: 'Licenças STFC' },
    { label: 'Relatórios STFC' }
  ],
  'RELATÓRIO ECONÔMICO': [
    { label: 'NOVO RELATORIO PRIMEIRO SEMESTRE' },
    { label: 'NOVO RELATORIO SEGUNDO SEMESTRE' },
    { label: 'Exportar Dados' }
  ],
  INFRA: [
    { label: 'ESTAÇÕES' },
    { label: 'ENLACES PRÓPRIOS' },
    { label: 'ENLACES CONTRATADOS' },
    { label: 'ACOMPANHAMENTO' }
  ]
};
